"use client";
import * as React from "react";
import { switchAnatomy } from "@tessera/core";
import { useControllableState } from "../utils/hooks";

export interface SwitchProps {
  label: React.ReactNode;
  checked?: boolean;
  defaultChecked?: boolean;
  onCheckedChange?: (checked: boolean) => void;
  disabled?: boolean;
  name?: string;
  value?: string;
}

export const Switch = React.forwardRef<HTMLInputElement, SwitchProps>(function Switch(
  { label, checked, defaultChecked = false, onCheckedChange, disabled, name, value },
  ref
) {
  const [isChecked, setChecked] = useControllableState({
    value: checked,
    defaultValue: defaultChecked,
    onChange: onCheckedChange,
  });
  const state = isChecked ? "checked" : "unchecked";

  return (
    <label {...switchAnatomy.attrs("root")} data-disabled={disabled || undefined}>
      <input
        type="checkbox"
        role="switch"
        data-visually-hidden=""
        ref={ref}
        checked={isChecked}
        onChange={(event) => setChecked(event.target.checked)}
        disabled={disabled}
        name={name}
        value={value}
      />
      <span {...switchAnatomy.attrs("control")} data-state={state} aria-hidden>
        <span {...switchAnatomy.attrs("thumb")} />
      </span>
      <span {...switchAnatomy.attrs("label")}>{label}</span>
    </label>
  );
});

@layer tessera.recipes {
  [data-scope="switch"][data-part="root"] {
    display: inline-flex;
    align-items: center;
    gap: var(--ts-space-2);
    cursor: pointer;
  }

  [data-scope="switch"][data-part="root"][data-disabled] {
    cursor: not-allowed;
  }

  [data-scope="switch"][data-part="control"] {
    position: relative;
    width: 2.25rem;
    height: 1.25rem;
    border-radius: var(--ts-radius-full);
    background: var(--ts-bg-muted);
    border: 1px solid transparent;
    flex-shrink: 0;
    transition: background-color var(--ts-duration-normal) var(--ts-easing-standard);
  }

  [data-scope="switch"][data-part="control"][data-state="checked"] {
    background: var(--ts-accent-default);
  }

  [data-scope="switch"][data-part="thumb"] {
    position: absolute;
    top: 50%;
    left: 2px;
    width: 0.875rem;
    height: 0.875rem;
    border-radius: var(--ts-radius-full);
    background: var(--ts-color-white);
    transform: translateY(-50%);
    transition: left var(--ts-duration-normal) var(--ts-easing-standard);
    box-shadow: var(--ts-shadow-sm);
  }

  [data-scope="switch"][data-part="control"][data-state="checked"] [data-part="thumb"] {
    left: calc(100% - 0.875rem - 2px);
  }

  [data-scope="switch"][data-part="label"] {
    font-size: var(--ts-font-size-sm);
    color: var(--ts-fg-default);
    user-select: none;
  }
}
